"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([["1057"],{3359(e){e.exports=JSON.parse('{"version":{"pluginId":"dj","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"cursoDjSidebar":[{"type":"link","href":"/docu-dj/curso-dj/intro","label":"Bienvenido al Curso DJ","docId":"intro","unlisted":false},{"type":"category","label":"M\xf3dulo 1 - Fundamentos DJ","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docu-dj/curso-dj/modulo-1/clase-1","label":"Clase 1: \xbfQu\xe9 es ser DJ?","docId":"modulo-1/clase-1","unlisted":false},{"type":"link","href":"/docu-dj/curso-dj/modulo-1/clase-2","label":"Clase 2: Tipos de DJ","docId":"modulo-1/clase-2","unlisted":false},{"type":"link","href":"/docu-dj/curso-dj/modulo-1/clase-3","label":"Clase 3: BPM (Tempo)","docId":"modulo-1/clase-3","unlisted":false},{"type":"link","href":"/docu-dj/curso-dj/modulo-1/clase-4","label":"Clase 4: Comp\xe1s y conteo","docId":"modulo-1/clase-4","unlisted":false}],"href":"/docu-dj/curso-dj/modulo-1/intro"},{"type":"category","label":"M\xf3dulo 2 - T\xe9cnicas de Mezcla","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docu-dj/curso-dj/modulo-2/clase-1","label":"Clase 1: Beat Matching","docId":"modulo-2/clase-1","unlisted":false},{"type":"link","href":"/docu-dj/curso-dj/modulo-2/clase-2","label":"Clase 2: Transiciones B\xe1sicas","docId":"modulo-2/clase-2","unlisted":false}],"href":"/docu-dj/curso-dj/modulo-2/intro"},{"type":"category","label":"M\xf3dulo 3 - Selecta y Programaci\xf3n","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docu-dj/curso-dj/modulo-3/clase-1","label":"Clase 1: Construcci\xf3n de Sesiones","docId":"modulo-3/clase-1","unlisted":false},{"type":"link","href":"/docu-dj/curso-dj/modulo-3/clase-2","label":"Clase 2: Lectura de Audiencia","docId":"modulo-3/clase-2","unlisted":false}],"href":"/docu-dj/curso-dj/modulo-3/intro"},{"type":"category","label":"M\xf3dulo 4 - Producci\xf3n y Efectos","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docu-dj/curso-dj/modulo-4/clase-1","label":"Clase 1: Efectos DJ B\xe1sicos","docId":"modulo-4/clase-1","unlisted":false},{"type":"link","href":"/docu-dj/curso-dj/modulo-4/clase-2","label":"Clase 2: Introducci\xf3n a la Producci\xf3n","docId":"modulo-4/clase-2","unlisted":false}],"href":"/docu-dj/curso-dj/modulo-4/intro"}]},"docs":{"intro":{"id":"intro","title":"Bienvenido al Curso DJ","description":"Este no es un curso para aprender a \u201Cusar una controladora\u201D o mezclar por intuici\xf3n. Es un programa dise\xf1ado para formar DJs con criterio, t\xe9cnica y visi\xf3n profesional.","sidebar":"cursoDjSidebar"},"modulo-1/clase-1":{"id":"modulo-1/clase-1","title":"Clase 1: \xbfQu\xe9 es ser DJ?","description":"Cuando la mayor\xeda de personas piensan en un DJ, imaginan a alguien poniendo m\xfasica en una fiesta, pero esa definici\xf3n est\xe1 incompleta. Un DJ es un artista que selecciona, mezcla y controla la energ\xeda de un p\xfablico a trav\xe9s de la m\xfasica.","sidebar":"cursoDjSidebar"},"modulo-1/clase-2":{"id":"modulo-1/clase-2","title":"Clase 2: Tipos de DJ","description":"No todos los DJs hacen lo mismo. Aunque todos usan m\xfasica como herramienta, el contexto, el p\xfablico y el objetivo pueden cambiar completamente la forma de mezclar. Entender los tipos de DJ te ayuda a algo clave:","sidebar":"cursoDjSidebar"},"modulo-1/clase-3":{"id":"modulo-1/clase-3","title":"Clase 3: BPM (Tempo)","description":"Antes de aprender a mezclar, necesitas entender algo fundamental: el tempo. Este t\xe9rmino hace referencia a la velocidad de la m\xfasica, velocidad que puede variar entre ritmos lentos o r\xe1pidos, dependiendo del g\xe9nero musical. Adem\xe1s, es importante tener en cuenta que el tempo se expresa por medio de una unidad de medida llamada BPM.","sidebar":"cursoDjSidebar"},"modulo-1/clase-4":{"id":"modulo-1/clase-4","title":"Clase 4: Comp\xe1s y conteo","description":"Si el BPM te dice qu\xe9 tan r\xe1pida es una canci\xf3n, el conteo te dice c\xf3mo est\xe1 organizada. Aqu\xed es donde realmente empiezas a pensar como DJ. Porque mezclar no es solo alinear velocidades, es alinear estructuras.","sidebar":"cursoDjSidebar"},"modulo-1/intro":{"id":"modulo-1/intro","title":"M\xf3dulo 1: Fundamentos del DJing","description":"---","sidebar":"cursoDjSidebar"},"modulo-2/clase-1":{"id":"modulo-2/clase-1","title":"Clase 1: Beat Matching","description":"Aprende a sincronizar el tempo de dos canciones para crear mezclas fluidas.","sidebar":"cursoDjSidebar"},"modulo-2/clase-2":{"id":"modulo-2/clase-2","title":"Clase 2: Transiciones B\xe1sicas","description":"Domina las transiciones entre canciones para mantener el flujo musical.","sidebar":"cursoDjSidebar"},"modulo-2/intro":{"id":"modulo-2/intro","title":"Resumen del M\xf3dulo 2","description":"Este m\xf3dulo se centra en t\xe9cnicas de mezcla para realizar transiciones limpias y mantener la energ\xeda del set.","sidebar":"cursoDjSidebar"},"modulo-3/clase-1":{"id":"modulo-3/clase-1","title":"Clase 1: Construcci\xf3n de Sesiones","description":"Aprende a organizar y construir una sesi\xf3n musical efectiva.","sidebar":"cursoDjSidebar"},"modulo-3/clase-2":{"id":"modulo-3/clase-2","title":"Clase 2: Lectura de Audiencia","description":"Desarrolla la habilidad de leer la audiencia y adaptar tu set en tiempo real.","sidebar":"cursoDjSidebar"},"modulo-3/intro":{"id":"modulo-3/intro","title":"Resumen del M\xf3dulo 3","description":"Aqu\xed trabajar\xe1s la construcci\xf3n de sets y la lectura de audiencia para tomar mejores decisiones en vivo.","sidebar":"cursoDjSidebar"},"modulo-4/clase-1":{"id":"modulo-4/clase-1","title":"Clase 1: Efectos DJ B\xe1sicos","description":"Conoce y practica los efectos m\xe1s comunes en DJ.","sidebar":"cursoDjSidebar"},"modulo-4/clase-2":{"id":"modulo-4/clase-2","title":"Clase 2: Introducci\xf3n a la Producci\xf3n","description":"Primeros pasos en la creaci\xf3n de tu propia m\xfasica electr\xf3nica.","sidebar":"cursoDjSidebar"},"modulo-4/intro":{"id":"modulo-4/intro","title":"Resumen del M\xf3dulo 4","description":"Este m\xf3dulo introduce efectos y bases de producci\xf3n para ampliar tu perfil como DJ.","sidebar":"cursoDjSidebar"}}}}')}}]);